    beginnerMoves:["اذكر الجمهور والاستخدام المقصود بوضوح.","حدّد شكل النجاح المطلوب.","عيّن الصيغة والنبرة والطول وما الذي يجب تجنبه."],
    advancedMoves:["اطلب المخطط أولًا، ثم وافق عليه، ثم اطلب المسودة الكاملة.","افصل بين الحقائق والتفسير.","قدّم معيار تقييم ليقيّم نفسه وفقه."],
    commonMistakes:["مطالبة النموذج بنتيجة مخصصة من خلال Prompt من ثلاث كلمات فقط.","فرض قيود كثيرة جدًا دفعة واحدة.","السؤال بصيغة «هل يمكنك...؟» بدل التعليمات المباشرة."],
    promptExamples:[{prompt:"الهدف: ___. السياق: ___. القيود: ___. المطلوب: ___.",why:"هيكل عام يصلح لمعظم الحالات."},{prompt:"أعطني المخطط أولًا. لا تكتب المسودة بعد.",why:"يمنع إعادة كتابة كاملة بسبب بنية خاطئة."},{prompt:"قبل أن تكتب، أخبرني ما الذي تحتاج إلى معرفته.",why:"يجعل النموذج يطرح أسئلة توضيحية."},{prompt:"اكتب بصوت [دور معيّن] يشرح لـ [جمهور معيّن].",why:"يثبت النبرة والعمق."}],
    beforeAfter:{before:"اكتب لي خطاب تغطية.",after:"خطاب تغطية لوظيفة Strategy Analyst في McKinsey. أنا طالب دراسات عليا في الإدارة الدولية ولدي خبرة في SOP وCRM. النبرة واثقة من دون غرور. 350 كلمة. تجنب عبارة: «أنا شغوف بـ...».",improvement:"حددت الوظيفة والخلفية والنبرة والطول وما يجب تجنبه."},
